using Microsoft.AspNetCore.Components;
using sv_d8950d3921b6487c93a12c1854bdcaa2.Models;
using sv_d8950d3921b6487c93a12c1854bdcaa2.Services;

namespace sv_d8950d3921b6487c93a12c1854bdcaa2.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles session identification across
/// the prerender → interactive boundary using PersistentComponentState, and
/// loads/saves wizard data from the singleton WizardStateStore.
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] private IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] private PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;

    protected string SessionId { get; private set; } = "";
    protected ApplicationFormData FormData { get; private set; } = new();

    private IDisposable? _persistingSubscription;

    protected abstract int StepNumber { get; }

    protected override void OnInitialized()
    {
        _persistingSubscription = PersistentState.RegisterOnPersisting(PersistState);

        if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restoredId)
            && restoredId is not null)
        {
            // Interactive render — session ID was persisted during prerender.
            SessionId = restoredId;
        }
        else if (HttpContextAccessor.HttpContext is { } httpContext)
        {
            // Prerender — HttpContext is available.
            var id = httpContext.Session.GetString("WizardId");
            if (id is null)
            {
                id = Guid.NewGuid().ToString();
                httpContext.Session.SetString("WizardId", id);
            }
            SessionId = id;
        }

        FormData = Store.GetOrCreate(SessionId);
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("wizardSessionId", SessionId);
        return Task.CompletedTask;
    }

    protected void SaveAndNavigate(string nextUrl)
    {
        if (FormData.CompletedStep < StepNumber)
        {
            FormData.CompletedStep = StepNumber;
        }
        Navigation.NavigateTo(nextUrl);
    }

    public void Dispose()
    {
        _persistingSubscription?.Dispose();
    }
}

