        <p><strong>Email:</strong> @FormData.PersonalInfo.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Work Experience</strong></div>
    <div class="card-body">
        @if (FormData.Experience.Count == 0)
        {
            <p class="text-muted">No entries provided.</p>
        }
        else
        {
            @foreach (var entry in FormData.Experience)
            {
                <div class="mb-2">
                    <strong>@entry.Title</strong> at @entry.Company
                    <span class="text-muted">(@entry.Duration)</span>
                </div>
            }
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>References</strong></div>
    <div class="card-body">
        @if (FormData.References.Count == 0)
        {
            <p class="text-muted">No references provided.</p>
        }
        else
        {
            @foreach (var refContact in FormData.References)
            {
                <div class="mb-2">
                    <strong>@refContact.Name</strong> &mdash; @refContact.Relationship
                    <br /><small class="text-muted">@refContact.Email</small>
                </div>
            }
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Previous">&larr; Previous</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        Your application has been submitted successfully!
    </div>
}

@code {
    protected override int StepNumber => 4;

    private bool _submitted;

    private void Previous() => Navigation.NavigateTo("/apply/references");

    private void Submit()
    {
        SaveAndNavigate("/apply/review");
        _submitted = true;
    }
}

