﻿@inherits LayoutComponentBase
@inject NavigationManager Navigation
@inject IHttpContextAccessor HttpContextAccessor
@inject WizardStateStore Store

@{
    var path = new Uri(Navigation.Uri).AbsolutePath;
    var isWizardPage = path.StartsWith("/apply/");

    var currentStep = path switch
    {
        "/apply/personal-info" => 1,
        "/apply/experience" => 2,
        "/apply/references" => 3,
        "/apply/review" => 4,
        _ => 0
    };

    var completedStep = 0;
    if (isWizardPage)
    {
        var sessionId = HttpContextAccessor.HttpContext?.Session.GetString("WizardId");
        if (sessionId is not null)
        {
            completedStep = Store.GetOrCreate(sessionId).CompletedStep;
        }
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (isWizardPage)
            {
                <nav class="wizard-progress" aria-label="Application progress">
                    @{
                        var steps = new (int Num, string Label, string Href)[]
                        {
                            (1, "Personal Info", "/apply/personal-info"),
                            (2, "Experience", "/apply/experience"),
                            (3, "References", "/apply/references"),
                            (4, "Review", "/apply/review"),
                        };
                    }
                    @foreach (var step in steps)
                    {
                        var isCompleted = step.Num <= completedStep;
                        var isCurrent = step.Num == currentStep;
                        var isAccessible = step.Num <= completedStep + 1;

                        var badgeClass = isCurrent ? "bg-primary"
                            : isCompleted ? "bg-success"
                            : "bg-secondary";

                        <span class="wizard-step @(isCurrent ? "active" : "")">
                            @if (isAccessible)
                            {
                                <a href="@step.Href" class="text-decoration-none">
                                    <span class="badge rounded-pill @badgeClass">@step.Num</span>
                                    <span class="wizard-label @(isCurrent ? "fw-bold" : "")">@step.Label</span>
                                </a>
                            }
                            else
                            {
                                <span class="text-muted">
                                    <span class="badge rounded-pill @badgeClass">@step.Num</span>
                                    <span class="wizard-label">@step.Label</span>
                                </span>
                            }
                        </span>

                        @if (step.Num < steps.Length)
                        {
                            <span class="wizard-separator text-muted">&rsaquo;</span>
                        }
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

::deep .wizard-progress {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    flex: 1;
}

::deep .wizard-step a {
    color: inherit;
}

::deep .wizard-separator {
    font-size: 1.2rem;
}

::deep .wizard-label {
    font-size: 0.85rem;
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

